### Visual States

```rust
enum FieldState {
    Normal,
    Focused,
    Error(String),
    Success,
    Disabled,
}

fn field_style(state: FieldState) -> Style {
    match state {
        FieldState::Normal => Style::new()
            .fg(fg::PRIMARY)
            .bg(bg::SURFACE),
        FieldState::Focused => Style::new()
            .fg(fg::PRIMARY)
            .bg(bg::HIGHLIGHT)
            .add_modifier(Modifier::BOLD),
        FieldState::Error(_) => Style::new()
            .fg(status::ERROR)
            .bg(bg::SURFACE),
        FieldState::Success => Style::new()
            .fg(status::SUCCESS)
            .bg(bg::SURFACE),
        FieldState::Disabled => Style::new()
            .fg(fg::MUTED)
            .bg(bg::SURFACE)
            .add_modifier(Modifier::DIM),
    }
}
