#[cfg(test)]
mod perf_screen_tests {
    use super::*;

    #[test]
    fn performance_shows_fps() {
        let state = PerformanceState::new();
        let mut pool = GraphemePool::new();
        let mut frame = Frame::new(120, 40, &mut pool);

        state.view(&mut frame, Rect::new(0, 0, 120, 40));

        // Should show FPS somewhere
    }

    #[test]
    fn performance_stress_test_runs() {
        let mut state = PerformanceState::new();
        state.start_stress_test();

        for _ in 0..10 {
            state.tick();
        }

        // Should still be running
        assert!(state.is_stress_testing());
    }

    #[test]
    fn virtualized_list_handles_large_data() {
        let mut state = PerformanceState::new();
        state.set_list_size(100_000);

        let mut pool = GraphemePool::new();
        let mut frame = Frame::new(120, 40, &mut pool);

        // Should render without hanging
        state.view(&mut frame, Rect::new(0, 0, 120, 40));
    }

    #[test]
    fn scroll_performance_is_acceptable() {
        let mut state = PerformanceState::new();
        state.set_list_size(100_000);

        let start = std::time::Instant::now();
        for _ in 0..100 {
            state.scroll_down();
        }
        let elapsed = start.elapsed();

        // Scrolling 100 items should take < 100ms
        assert!(elapsed.as_millis() < 100);
    }
}
